var processChunks = function(s, n) {
    var parts = [];
    for (var i = 0; i < s.length; i += n) {
        var chunk = s.substring(i, Math.min(i + n, s.length));
        // 记录每个字符最后出现的位置
        var last = {};
        for (var j = 0; j < chunk.length; j++) {
            last[chunk[j]] = j;
        }
        // 只保留「最后出现」的字符
        var deduped = '';
        for (var j = 0; j < chunk.length; j++) {
            if (last[chunk[j]] === j) {
                deduped += chunk[j];
            }
        }
        parts.push(deduped);
    }
    return parts.join('');
};
