```c
char* processChunks(char* s, int n) {
    int len = strlen(s);
    int max_result = len + 1;
    char* result = (char*)malloc(max_result);
    int pos = 0;

    for (int i = 0; i < len; i += n) {
        int end = i + n;
        if (end > len) end = len;
        int chunk_len = end - i;

        // 记录每个字符最后出现的位置
        int last[256];
        memset(last, -1, sizeof(last));
        for (int j = 0; j < chunk_len; j++) {
            last[(unsigned char)s[i + j]] = j;
        }

        // 只保留「最后出现」的字符
        for (int j = 0; j < chunk_len; j++) {
            if (last[(unsigned char)s[i + j]] == j) {
                result[pos++] = s[i + j];
            }
        }
    }
    result[pos] = '\0';
    return result;
}
